When('the user submits the fleet registration form', async function () {
  // The fleet registration page has multiple button[type="submit"] elements:
  //   1. button.search-submit  — hidden, in the site search form (WRONG — submits search)
  //   2. button.btn.submit     — visible, "Submit enquiry", in form.fleet-registration (CORRECT)
  // DO NOT use a broad selector like 'button[type="submit"]'.first() — that grabs the
  // hidden search button first in DOM order, submitting the wrong form.
  // Fleet form is a GET form (not POST) — submission causes a same-URL page navigation
  // that returns the thank-you message inline.
  const SUBMIT_SEL = 'form.fleet-registration button[type="submit"], button.btn.submit';
  const submitBtn = this.page.locator(SUBMIT_SEL).first();
  if ((await submitBtn.count()) > 0) {
    await submitBtn.scrollIntoViewIfNeeded().catch(() => {});
    await submitBtn.waitFor({ state: 'visible', timeout: 10000 });
    // Trigger click and wait for the resulting page load together
    await Promise.all([
      this.page.waitForLoadState('domcontentloaded', { timeout: 30000 }).catch(() => {}),
      this.page.click(SUBMIT_SEL, { timeout: 10000 }),
    ]);
    console.log('📋 Fleet registration form submitted');
  } else {
    console.warn('⚠️  Submit button not found — attempting form.submit()');
    await this.page.evaluate(() => {
      const form = document.querySelector('form.fleet-registration, form[action*="fleet"]');
      if (form) form.submit();
    });
    await this.page.waitForLoadState('domcontentloaded', { timeout: 30000 }).catch(() => {});
  }
  await this.page.waitForTimeout(2000);
});

