Then('all form fields should have associated labels', async function () {
  const inputs = this.page.locator('input:visible');
  const count = await inputs.count();
  let accessibleCount = 0;
  for (let i = 0; i < Math.min(count, 10); i++) {
    const input = inputs.nth(i);
    const id = await input.getAttribute('id').catch(() => null);
    const ariaLabel = await input.getAttribute('aria-label').catch(() => null);
    const placeholder = await input.getAttribute('placeholder').catch(() => null);
    if (id || ariaLabel || placeholder) accessibleCount++;
  }
  assert.ok(accessibleCount > 0 || count === 0, 'Labels should be associated with inputs');
});

